  ('investigation-d5dfc642-moex-00093', 'investigation-d5dfc642', 'investigation-d5dfc642-moex-112-3082b5f1', 'sub-investigation-d5dfc642-05', NULL, 'essay', '甲居住於臺北市，原為位於新北市 A 幼兒園之教保服務人員。甲於 110
年 5 月間因體罰幼生乙致其身體受傷而遭人向新北市主管機關 B檢舉，
經 B 查證屬實而將甲移送法辦，並經地方法院刑事判決成立過失傷害
罪，處拘役 15 日。判決之後 B 另依行為時法規規定，作成甲 3 年不得
於教保服務機構服務之行政處分。甲主張該處分違法，因其居住於臺北
市，B 就本案並無管轄權；且地方法院已判處其拘役，該處分違反一事
不二罰原則。試問：甲之主張是否有理由？請附具理由說明之。（25 分）
相關法條：
行為時教保服務人員條例第 12 條第 1 項第 2 款規定：「教保服務人員有下列情事
之一者，不得在幼兒園服務：……二、行為違反相關法令，損害兒童權益情節重大，
經有關機關查證屬實。」
行為時教保服務機構不適任人員認定通報資訊蒐集及查詢處理利用辦法第 3 條第
2 項規定：「教保服務人員不適任之通報、資訊之蒐集及查詢，依幼兒園不適任教
保服務人員之通報與資訊蒐集及查詢辦法規定辦理；其疑似不適任之通報及不適
任情事之認定，準用第8條至第11條規定辦理。」第10條第2項規定：「調查屬
實之案件經有管轄權機關通知直轄市、縣(市)主管機關後，直轄市、縣(市)主管機
關應送直轄市、縣(市)主管機關之性別平等教育委員會或由直轄市、縣(市)主管機
關組成之委員會(以下簡稱認定委員會)，依本法第23條第1項第2款、第3款或
第24條第1項第1款規定認定是否構成應予免職、解聘、解僱、廢止教保服務機
構設立許可或令其更換人員之情事，並審酌案件情節，認定 1 年至 4 年不得進用
或僱用之期間；必要時，性別平等教育委員會或認定委員會得組成調查小組調查認
定。」', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:49+00:00", "source_pdf_sha1": "685bff20fd53", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "409", "s": "0303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "法律實務組"}'::jsonb, NULL),
